INSERT INTO phrases (category, turkish, german, pronunciation, sort_order, formality) VALUES
('Vorstellung', 'Almanya''dan geliyoruz, kocam Türk, ben Almanyalıyım.', 'Wir kommen aus Deutschland, mein Mann ist Türke, ich bin Deutsche.', 'Al-man-ja-dan ge-li-jo-ruz ko-dsham Türk ben Al-man-ja-ly-jym', 7, 'both'),
('Vorstellung', 'O dört yıldan fazladır burada yaşıyor, ben ise yarım yıldır.', 'Er lebt seit über 4 Jahren hier, ich seit einem halben Jahr.', 'O dört yyl-dan fas-la-dyr bu-ra-da ja-schy-jor ben i-se ja-rym yyl-dyr', 8, 'both'),
('Vorstellung', 'Kocam pizzacı ve fırın ustası.', 'Mein Mann ist Pizzabäcker und Bäckermeister.', 'Ko-dsham piz-za-dschy ve fy-ryn us-ta-sy', 9, 'both');
